INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.A1.1', 'Strand A: Literacy Connections and Applications', 'Receptive and Expressive Communication: analyze and explain how transferable skills can be used to support communication in various cultural, social, linguistic, and domain-specific contexts, and apply them when reading, listening to, viewing, and creating texts of various forms', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.A1.2', 'Strand A: Literacy Connections and Applications', 'Student Agency and Engagement: evaluate and explain how transferable skills help them to express their voice, be engaged in their learning, and implement a plan to develop their capabilities and potential', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.A2', 'Strand A: Literacy Connections and Applications — Digital Media Literacy', 'demonstrate and apply the knowledge and skills needed to interact safely and responsibly in online environments, use digital and media tools to construct knowledge, and demonstrate learning as critical consumers and creators of media', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.A2.1', 'Strand A: Literacy Connections and Applications', 'Digital Citizenship: evaluate and explain their rights and responsibilities when interacting online with appropriate permission, and make decisions that contribute positively to the development of their digital identity and those of their communities', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.A2.2', 'Strand A: Literacy Connections and Applications', 'Online Safety, Well-Being, and Etiquette: demonstrate an understanding of how to navigate online environments safely, manage their privacy, personal data, and security, and interact in a way that supports their well-being and that of others, including seeking appropriate permission', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.A2.3', 'Strand A: Literacy Connections and Applications', 'Research and Information Literacy: conduct research, considering accuracy, credibility, and perspectives, with a focus on misinformation, disinformation, and curated information, to construct knowledge, create texts, and demonstrate learning, while respecting legal and ethical considerations', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.A2.4', 'Strand A: Literacy Connections and Applications', 'Forms, Conventions, and Techniques: evaluate the use of the various forms, conventions, and techniques of digital and media texts, consider the impact on the audience, and apply this understanding when analyzing and creating texts', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.A2.5', 'Strand A: Literacy Connections and Applications', 'Media, Audience, and Production: demonstrate an understanding of the interrelationships between the form, message, and context of texts, the intended and unintended audience, and the purpose for production', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.A2.6', 'Strand A: Literacy Connections and Applications', 'Innovation and Design: select and use appropriate digital and media tools to support the design process and address authentic, relevant, real-world problems by developing and proposing innovative solutions', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.A2.7', 'Strand A: Literacy Connections and Applications', 'Community and Cultural Awareness: communicate and collaborate with various communities in a safe, respectful, responsible, and inclusive manner when using online platforms and environments, including digital and media tools, and demonstrate and model cultural awareness with members of the community', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.A3', 'Strand A: Literacy Connections and Applications — Applications, Connections, and Contributions', 'apply language and literacy skills in cross-curricular and integrated learning, and demonstrate an understanding of, and make connections to, diverse voices, experiences, perspectives, histories, and contributions, including those of First Nations, Métis, and Inuit individuals, communities, groups, and nations', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.A3.1', 'Strand A: Literacy Connections and Applications', 'Cross-Curricular and Integrated Learning: analyze and explain how the knowledge and skills developed in this course support learning in various subject areas and in everyday life, and describe how they enhance understanding and communication', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.A3.2', 'Strand A: Literacy Connections and Applications', 'Identity and Community: demonstrate an understanding of the historical contexts, contributions, lived experiences and perspectives of a diversity of individuals and communities, including those in Canada, by exploring and analyzing the concepts of identity, self, and sense of belonging in a variety of culturally responsive and relevant texts', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.A3.3', 'Strand A: Literacy Connections and Applications', 'First Nations, Métis, and Inuit Perspectives and Ways of Knowing: analyze themes explored in First Nations, Métis, and Inuit cultures to demonstrate an understanding of the varied identities, perspectives, relationships, legacies, truths, and ways of knowing, being, and doing STRAND B. Foundations of Language', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.B1', 'Strand B: Foundations of Language — Oral and Non-Verbal Communication', 'apply listening, speaking, and non-verbal communication skills and strategies to understand and communicate meaning in formal and informal contexts and for various purposes and audiences', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.B1.1', 'Strand B: Foundations of Language', 'Effective Listening Skills: evaluate and use various effective listening skills to enhance comprehension, including paraphrasing, asking open-ended questions, making relevant responses in group discussions, and reflecting on what has been said, and use these skills in formal and informal contexts and for various purposes', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.B1.2', 'Strand B: Foundations of Language', 'Listening Strategies for Comprehension: select and use a variety of listening strategies before, during, and after listening to analyze and comprehend information communicated orally and non-verbally, seek clarification, and identify relevant evidence to support a response appropriate to the context', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.B1.3', 'Strand B: Foundations of Language', 'Speaking Purpose and Strategies: analyze the purpose and audience for speaking in formal and informal contexts, and select and adapt speaking strategies to communicate clearly and coherently', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.B1.4', 'Strand B: Foundations of Language', 'Oral and Non-Verbal Communication Strategies: identify and use oral and non-verbal communication strategies, including expression, gestures, and body language, and evaluate and compare the effectiveness of these strategies in supporting understanding or communication, including how their use may vary across cultures', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.B1.5', 'Strand B: Foundations of Language', 'Word Choice, Syntax, and Grammar in Oral Communication: use precise and descriptive word choice, including domain-specific vocabulary from various subjects, and cohesive and coherent sentences during formal and informal communication, to support audience comprehension', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.B2', 'Strand B: Foundations of Language — Language Foundations for Reading and Writing', 'demonstrate an understanding of foundational language knowledge and skills, and apply this understanding when reading and writing', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.B2.1', 'Strand B: Foundations of Language', 'Word-Level Reading and Spelling: Using Morphological Knowledge: use consolidated knowledge of the meanings of words and morphemes (i.e., bases, prefixes, and suffixes) to read and spell complex words with accuracy and automaticity', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.B2.2', 'Strand B: Foundations of Language', 'Vocabulary: demonstrate an understanding of a wide variety of words, acquire and use explicitly taught vocabulary flexibly in various contexts, including other subject areas, and use consolidated morphological knowledge to analyze and understand new words in context', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.B2.3', 'Strand B: Foundations of Language', 'Reading Fluency: Accuracy, Rate, and Prosody: read a variety of complex texts fluently, with accuracy and appropriate pacing to support comprehension, and when reading aloud, adjust expression and intonation according to the purpose of reading 2 | The Ontario Curriculum: English, Grade 9, De-streamed, 2023', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.B3', 'Strand B: Foundations of Language — Language Conventions for Reading and Writing', 'demonstrate an understanding of sentence structure, grammar, cohesive ties, and capitalization and punctuation, and apply this knowledge when reading and writing sentences, paragraphs, and a variety of texts*', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.B3.1', 'Strand B: Foundations of Language', 'Syntax and Sentence Structure: use their knowledge of sentence types and forms to construct complex sentences that connect and communicate ideas accurately and effectively', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.B3.2', 'Strand B: Foundations of Language', 'Grammar: demonstrate an understanding of the functions of parts of speech in sentences, consolidate and refine their understanding of grammar, and use this knowledge to support comprehension and communicate meaning clearly and precisely', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.B3.3', 'Strand B: Foundations of Language', 'Capitalization and Punctuation: use and refine their understanding of the meaning and function of capitalization and punctuation to communicate meaning clearly and coherently, when reading and writing STRAND C. Comprehension: Understanding and Responding to Texts', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C1', 'Strand C: Comprehension: Understanding and Responding to Texts — Knowledge about Texts', 'apply foundational knowledge and skills to understand a variety of texts, including digital and media texts, by creators with diverse identities, perspectives, and experience, and demonstrate an understanding of the patterns, features, and elements of style associated with various text forms and genres', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C1.1', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Using Foundational Knowledge and Skills to Comprehend Texts: read and comprehend various complex texts, using knowledge of words, grammar, cohesive ties, sentence structures, and background knowledge', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C1.2', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Text Forms and Genres: analyze and compare the characteristics of various text forms and genres, including cultural text forms, and provide evidence to explain how they help communicate meaning', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C1.3', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Text Patterns and Features: compare the text patterns, such as compare and contrast in an expository essay, and text features, such as footnotes and copyright information, associated with different text forms, including cultural texts, and evaluate their importance in helping readers, listeners, and viewers understand the meaning', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C1.4', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Visual Elements of Texts: evaluate how images, graphics, and visual design create, communicate, and contribute to meaning in a variety of texts', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C1.5', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Elements of Style: identify various elements of style in texts, including voice, word choice, word patterns, and sentence structure, and analyze how each element helps create meaning and is appropriate for the text form and genre', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C1.6', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Point of View: analyze the narrator’s point of view, including limited, omniscient, or unreliable, in a variety of texts, explain how it is communicated, and suggest alternative points of view, giving reasons', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C1.7', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Indigenous Context of Various Text Forms: read, listen to, and view a wide variety of text forms by diverse First Nations, Métis, and Inuit creators to make meaning through Indigenous Storywork about First Nations, Métis, and Inuit histories, cultures, relationships, communities, groups, nations, and lived experiences', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C2', 'Strand C: Comprehension: Understanding and Responding to Texts — Comprehension Strategies', 'apply comprehension strategies before, during, and after reading, listening to, and viewing a variety of texts, including digital and media texts, by creators with diverse identities, perspectives, and experience, in order to understand and clarify the meaning of texts', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C2.1', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Prereading: Activating Prior Knowledge: identify and explain prior knowledge from various sources, including personal experiences and learning in other subject areas, that they can use to make connections and understand new texts', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C2.2', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Prereading: Identifying the Purpose for Reading, Listening, and Viewing: identify a variety of purposes for engaging with texts, select texts from diverse creators that are suitable for the purposes, and explain why the selections are appropriate', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C2.3', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Monitoring of Understanding: Making and Confirming Predictions: make predictions using background knowledge and textual information, pose questions to confirm or refute their predictions, and revise or refine their understanding as indicated', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C2.4', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Monitoring of Understanding: Ongoing Comprehension Check: select suitable strategies, such as rereading, using the glossary, asking questions, and consulting references and other resources, to monitor and confirm their understanding of complex texts and solve comprehension problems * For an at-a-glance view of the mandatory learning in B3 across grades, see the appendix in the English curriculum. 3 | The Ontario Curriculum: English, Grade 9, De-streamed, 2023', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C2.5', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Monitoring of Understanding: Making Connections: connect, compare, and contrast the ideas expressed in texts and their knowledges and lived experiences, the ideas in other texts, and the world around them', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C2.6', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Summarizing: Identifying Relevant information and Drawing Conclusions: summarize and synthesize the important ideas and supporting details in complex texts, and draw effective conclusions', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C2.7', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Reflecting on Learning: explain and compare how various strategies, such as visualizing, making predictions, summarizing, and connecting to their experiences, have helped them comprehend various texts, and set goals for future improvement', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C3', 'Strand C: Comprehension: Understanding and Responding to Texts — Critical Thinking in Literacy', 'apply critical thinking skills to deepen understanding of texts, and analyze how various perspectives and topics are communicated and addressed in a variety of texts, including digital, media, and cultural texts', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C3.1', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Literary Devices: analyze literary devices, including allusion, analogy, juxtaposition, and flashback, in a variety of texts, and explain how they help create meaning and are appropriate for the intended purpose and audience', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C3.2', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Making Inferences: make local and global inferences, using explicit and implicit evidence, to explain and support their interpretations about various complex texts', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C3.3', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Analyzing Texts: analyze complex texts, including literary and informational texts, by assessing the credibility, reliability, and significance of information and formulating conclusions', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C3.4', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Analyzing Cultural Elements of Texts: analyze cultural elements that are represented in various texts, including, norms, values, social hierarchy, past times, language, and taboos, by investigating the meanings of these elements, making connections to their lived experience and culture, and considering how the inclusion of these elements contributes to the meaning of the text', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C3.5', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Perspectives within Texts: analyze explicit and implicit perspectives communicated in various texts, evaluate any evidence that could show bias in these perspectives, and suggest ways to avoid any such bias', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C3.6', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Analysis and Response: explain how various topics, such as diversity, inclusion, and accessibility, are addressed in texts, respond to the insights and messages conveyed, and different positions presented', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C3.7', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Indigenous Contexts: compare the ways in which historical periods, cultural experiences, and/or socio-political conditions and events have influenced two or more texts created First Nations, Métis, and Inuit individuals, communities, groups, or nations, and how they relate to current lived experiences', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.C3.8', 'Strand C: Comprehension: Understanding and Responding to Texts', 'Reflecting on Learning: assess the effectiveness of the critical thinking skills they used when analyzing and evaluating various texts, and set goals to improve their use Strand D. Composition: Expressing Ideas and Creating Texts', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.D1', 'Strand D: Composition: Expressing Ideas and Creating Texts — Developing Ideas and Organizing Content', 'plan, develop ideas, gather information, and organize content for creating texts of various forms, including digital and media texts, on a variety of topics', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.D1.1', 'Strand D: Composition: Expressing Ideas and Creating Texts', 'Purpose and Audience: identify the topic, purpose, and audience for various texts they plan to create; choose a text form, genre, and medium to suit the purpose and audience, and justify their choices', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.D1.2', 'Strand D: Composition: Expressing Ideas and Creating Texts', 'Developing Ideas: generate and develop ideas and details about complex topics, such as topics related to diversity, equity, and inclusion and to other subject areas, using a variety of strategies, and drawing on various resources, including their own lived experiences', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.D1.3', 'Strand D: Composition: Expressing Ideas and Creating Texts', 'Research: gather and synthesize information and content relevant to a topic, using a variety of textual sources and appropriate strategies; evaluate the currency, quality, bias, and accuracy of information; verify the reliability of sources; and check copyright and cite the sources for all content created by others', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.D1.4', 'Strand D: Composition: Expressing Ideas and Creating Texts', 'Organizing Content: classify and sequence ideas and collected information, selecting effective strategies and tools, and identify and organize relevant content, evaluating the choices of text form, genre, and medium, and considering alternatives', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.D1.5', 'Strand D: Composition: Expressing Ideas and Creating Texts', 'Reflecting on Learning: evaluate the strategies and tools used to develop ideas and organize content for texts of the chosen forms, genres, and media, explain which were most helpful, and suggest steps for future improvement as a text creator 4 | The Ontario Curriculum: English, Grade 9, De-streamed, 2023', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.D2', 'Strand D: Composition: Expressing Ideas and Creating Texts — Creating Texts', 'apply knowledge and understanding of various text forms and genres to create, revise, edit, and proofread their own texts, using a variety of media, tools, and strategies, and reflect critically on created texts', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.D2.1', 'Strand D: Composition: Expressing Ideas and Creating Texts', 'Producing Drafts: draft complex texts of various forms and genres, including narrative, persuasive, expository, and informational texts, citing sources, and use a variety of appropriate media, tools, and strategies to transform information and communicate ideas', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.D2.2', 'Strand D: Composition: Expressing Ideas and Creating Texts', 'Printing, Handwriting, and Word Processing: write fluently, with a personal style, touch type quickly and accurately, and select and use appropriate word-processing programs and tools to produce texts of various lengths and complexity', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.D2.3', 'Strand D: Composition: Expressing Ideas and Creating Texts', 'Voice: establish an identifiable voice in their texts, modifying language, style, and tone to suit the text’s form, genre, audience, and purpose, and express their thoughts, feelings, and opinions about the topic clearly', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.D2.4', 'Strand D: Composition: Expressing Ideas and Creating Texts', 'Point of View and Perspective: explain the explicit and implicit points of view, perspectives, and bias conveyed in their texts, evaluate how various audiences might respond, and suggest ways to acknowledge other perspectives', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.D2.5', 'Strand D: Composition: Expressing Ideas and Creating Texts', 'Revision: make revisions to the content, elements of style, patterns, and features of draft texts, and add, delete, revise, and reorganize sentences to improve clarity, focus, and coherence, using various strategies and seeking and selectively using feedback', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.D2.6', 'Strand D: Composition: Expressing Ideas and Creating Texts', 'Editing and Proofreading: edit draft texts to improve accuracy and style, checking for errors in spelling, punctuation, grammar, and format; edit digital texts using word-processing software, including spell- and grammar-checkers', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.D3', 'Strand D: Composition: Expressing Ideas and Creating Texts — Publishing, Presenting, and Reflecting', 'select suitable and effective media, techniques, and tools to publish and present final texts, and critically analyze how well the texts address various topics', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.D3.1', 'Strand D: Composition: Expressing Ideas and Creating Texts', 'Producing Final Texts: produce final texts using appropriate techniques and tools, including digital design and production tools, to achieve the intended effect', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.D3.2', 'Strand D: Composition: Expressing Ideas and Creating Texts', 'Publishing and Presenting Texts: publish and present texts they have created, using various media and tools, and evaluate how their choices helped them communicate their intended message', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('English', '9', 'ENL1W.D3.3', 'Strand D: Composition: Expressing Ideas and Creating Texts', 'Reflecting on Learning: evaluate the strategies and tools they found helpful when publishing and presenting texts, reflect on what they learned at each stage of the creative process, analyze how their texts address various topics, and suggest steps for future improvement as a text creator 5 | The Ontario Curriculum: English, Grade 9, De-streamed, 2023 3202 ,oiratnO rof retnirP', 'Ontario ENL1W 2023', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.A1', 'Strand A: Mathematical Thinking and Making Connections — Mathematical Processes', 'apply the mathematical processes to develop a conceptual understanding of, and procedural fluency with, the mathematics they are learning', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.A2', 'Strand A: Mathematical Thinking and Making Connections — Making Connections', 'make connections between mathematics and various knowledge systems, their lived experiences, and various real-life applications of mathematics, including careers', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.AA1', 'Strand AA: Social-Emotional Learning Skills in Mathematics — Social-Emotional Learning Skills', 'develop and explore a variety of social-emotional learning skills in a context that supports and reflects this learning in connection with the expectations across all other strands', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.B1', 'Strand B: Number — Development of Numbers and Number Sets', 'demonstrate an understanding of the development and use of numbers, and make connections between sets of numbers', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.B1.1', 'Strand B: Number — Development and Use of Numbers', 'research a number concept to tell a story about its development and use in a specific culture, and describe its relevance in a current context', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.B1.2', 'Strand B: Number — Number Sets', 'describe how various subsets of a number system are defined, and describe similarities and differences between these subsets', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.B1.3', 'Strand B: Number — Number Sets', 'use patterns and number relationships to explain density, infinity, and limit as they relate to number sets', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.B2', 'Strand B: Number — Powers', 'represent numbers in various ways, evaluate powers, and simplify expressions by using the relationships between powers and their exponents', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.B2.1', 'Strand B: Number — Powers', 'analyse, through the use of patterning, the relationship between the sign and size of an exponent and the value of a power, and use this relationship to express numbers in scientific notation and evaluate powers', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.B2.2', 'Strand B: Number — Powers', 'analyse, through the use of patterning, the relationships between the exponents of powers and the operations with powers, and use these relationships to simplify numeric and algebraic expressions', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.B3', 'Strand B: Number — Number Sense and Operations', 'apply an understanding of rational numbers, ratios, rates, percentages, and proportions, in various mathematical contexts, and to solve problems', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.B3.1', 'Strand B: Number — Rational Numbers', 'apply an understanding of integers to describe location, direction, amount, and changes in any of these, in various contexts', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.B3.2', 'Strand B: Number — Rational Numbers', 'apply an understanding of unit fractions and their relationship to other fractional amounts, in various contexts, including the use of measuring tools', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.B3.3', 'Strand B: Number — Rational Numbers', 'apply an understanding of integers to explain the effects that positive and negative signs have on the values of ratios, rates, fractions, and decimals, in various contexts', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.B3.4', 'Strand B: Number — Applications', 'solve problems involving operations with positive and negative fractions and mixed numbers, including problems involving formulas, measurements, and linear relations, using technology when appropriate', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.B3.5', 'Strand B: Number — Applications', 'pose and solve problems involving rates, percentages, and proportions in various contexts, including contexts connected to real-life applications of data, measurement, geometry, linear relations, and financial literacy', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.C1', 'Strand C: Algebra — Algebraic Expressions and Equations', 'demonstrate an understanding of the development and use of algebraic concepts and of their connection to numbers, using various tools and representations', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.C1.1', 'Strand C: Algebra — Development and Use of Algebra', 'research an algebraic concept to tell a story about its development and use in a specific culture, and describe its relevance in a current context', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.C1.2', 'Strand C: Algebra — Algebraic Expressions and Equations', 'create algebraic expressions to generalize relationships expressed in words, numbers, and visual representations, in various contexts', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.C1.3', 'Strand C: Algebra — Algebraic Expressions and Equations', 'compare algebraic expressions using concrete, numerical, graphical, and algebraic methods to identify those that are equivalent, and justify their choices', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.C1.4', 'Strand C: Algebra — Algebraic Expressions and Equations', 'simplify algebraic expressions by applying properties of operations of numbers, using various representations and tools, in different contexts', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.C1.5', 'Strand C: Algebra — Algebraic Expressions and Equations', 'create and solve equations for various contexts, and verify their solutions', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.C2', 'Strand C: Algebra — Coding', 'apply coding skills to represent mathematical concepts and relationships dynamically, and to solve problems, in algebra and across the other strands', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.C2.1', 'Strand C: Algebra — Coding', 'use coding to demonstrate an understanding of algebraic concepts including variables, parameters, equations, and inequalities', 'Ontario MTH1W 2021', datetime('now'));
