INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.C2.3', 'Strand C: Algebra — Coding', 'read code to predict its outcome, and alter code to adjust constraints, parameters, and outcomes to represent a similar or new mathematical situation', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.C3', 'Strand C: Algebra — Application of Relations', 'represent and compare linear and non-linear relations that model real-life situations, and use these representations to make predictions', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.C3.1', 'Strand C: Algebra — Application of Linear and Non-Linear Relations', 'compare the shapes of graphs of linear and non-linear relations to describe their rates of change, to make connections to growing and shrinking patterns, and to make predictions', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.C3.2', 'Strand C: Algebra — Application of Linear and Non-Linear Relations', 'represent linear relations using concrete materials, tables of values, graphs, and equations, and make connections between the various representations to demonstrate an understanding of rates of change and initial values', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.C3.3', 'Strand C: Algebra — Application of Linear and Non-Linear Relations', 'compare two linear relations of the form y = ax + b graphically and algebraically, and interpret the meaning of their point of intersection in terms of a given context', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.C4', 'Strand C: Algebra — Characteristics of Relations', 'demonstrate an understanding of the characteristics of various representations of linear and non-linear relations, using tools, including coding when appropriate', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.C4.1', 'Strand C: Algebra — Characteristics of Linear and Non-Linear Relations', 'compare characteristics of graphs, tables of values, and equations of linear and non-linear relations', 'Ontario MTH1W 2021', datetime('now'));
