INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.C4.3', 'Strand C: Algebra — Characteristics of Linear and Non-Linear Relations', 'translate, reflect, and rotate lines defined by y = ax, where a is a constant, and describe how each transformation affects the graphs and equations of the defined lines', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.C4.4', 'Strand C: Algebra — Characteristics of Linear and Non-Linear Relations', 'determine the equations of lines from graphs, tables of values, and concrete representations of linear relations by making connections between rates of change and slopes, and between initial values and y- intercepts, and use these equations to solve problems', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.D1', 'Strand D: Data — Collection, Representation, and Analysis of Data', 'describe the collection and use of data, and represent and analyse data involving one and two variables', 'Ontario MTH1W 2021', datetime('now'));
