INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.D1.3', 'Strand D: Data — Representation and Analysis of Data', 'create a scatter plot to represent the relationship between two variables, determine the correlation between these variables by testing different regression models using technology, and use a model to make predictions when appropriate', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.D2', 'Strand D: Data — Mathematical Modelling', 'apply the process of mathematical modelling, using data and mathematical concepts from other strands, to represent, analyse, make predictions, and provide insight into real-life situations', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.D2.1', 'Strand D: Data — Application of Mathematical Modelling', 'describe the value of mathematical modelling and how it is used in real life to inform decisions', 'Ontario MTH1W 2021', datetime('now'));
