INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.D2.5', 'Strand D: Data — Process of Mathematical Modelling', 'report how the model can be used to answer the question of interest, how well the model fits the context, potential limitations of the model, and what predictions can be made based on the model', 'Ontario MTH1W 2021', datetime('now'));
INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.E1', 'Strand E: Geometry and Measurement — Geometric and Measurement Relationships', 'demonstrate an understanding of the development and use of geometric and measurement relationships, and apply these relationships to solve problems, including problems involving real-life situations', 'Ontario MTH1W 2021', datetime('now'));
