INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.F1', 'Strand F: Financial Literacy — Financial Decisions', 'demonstrate the knowledge and skills needed to make informed financial decisions', 'Ontario MTH1W 2021', datetime('now'));
