INSERT OR REPLACE INTO curriculum (subject, grade, standard_code, strand, description, source_version, ingested_at) VALUES ('Math', '9', 'MTH1W.F1.4', 'Strand F: Financial Literacy — Financial Decisions', 'modify budgets displayed in various ways to reflect specific changes in circumstances, and provide a rationale for the modifications', 'Ontario MTH1W 2021', datetime('now'));
